#!/usr/bin/env bash
set -euo pipefail
source "$(dirname "$0")/lib/common.sh"
serial=emulator-5554; while (($#)); do case "$1" in --serial) serial="${2:?}"; shift 2;; -h|--help) echo "usage: $0 [--serial SERIAL]"; exit 0;; *) archphene_die "unknown argument: $1";; esac; done
archphene_init_adb "$serial"; package=org.archpheneos.manager; archphene_adb_run shell am force-stop "$package"; archphene_adb_run shell am start -W -n "$package/.MainActivity" >/dev/null
archphene_wait_ui 'content-desc="Filter and sort apps"' repo-filter-home; ui="$ARCHPHENE_UI"; archphene_tap_ui_pattern "$ui" 'content-desc="Filter and sort apps"' filter; archphene_wait_ui 'text="Filter and sorting"' repo-filter-dialog; ui="$ARCHPHENE_UI"; archphene_tap_ui_pattern "$ui" 'text="(?:All apps|Updates available|Pinned versions)"' current-filter; archphene_wait_ui 'text="All apps"' repo-filter-options; ui="$ARCHPHENE_UI"; archphene_tap_ui_pattern "$ui" 'text="All apps"' all-apps; archphene_wait_ui 'text="APPLY"' repo-filter-apply; ui="$ARCHPHENE_UI"; archphene_tap_ui_pattern "$ui" 'text="APPLY"' apply; archphene_wait_ui 'content-desc="Add Linux app"' repo-all-apps; ui="$ARCHPHENE_UI"
if [[ "$ui" == *'text="btop"'* && "$ui" == *'text="Not installed"'* ]]; then archphene_tap_ui_pattern "$ui" 'text="btop"' stale-btop; archphene_wait_ui 'text="Remove from apps"' repo-stale-btop; ui="$ARCHPHENE_UI"; archphene_tap_ui_pattern "$ui" 'text="Remove from apps"' remove; archphene_wait_ui 'content-desc="Add Linux app"' repo-clean-home; ui="$ARCHPHENE_UI"; fi
archphene_tap_ui_pattern "$ui" 'content-desc="Add Linux app"' Add; archphene_wait_ui 'text="Search official Arch packages"' repo-add; ui="$ARCHPHENE_UI"; archphene_tap_ui_pattern "$ui" 'text="Search official Arch packages"' search-field; archphene_adb_run shell input text btop; sleep 1; ui="$(archphene_capture_ui repo-query)"; if [[ "$ui" == *'text="Try out your stylus"'* && "$ui" == *'text="Cancel"'* ]]; then archphene_tap_ui_pattern "$ui" 'text="Cancel"' 'Gboard stylus education Cancel'; sleep 1; fi; archphene_adb_run shell input keyevent KEYCODE_BACK; sleep 1; ui="$(archphene_capture_ui repo-query-stable)"; archphene_tap_ui_pattern "$ui" 'content-desc="Search package repositories"' search-button; archphene_wait_ui 'text="btop  [^"]+"' repo-results 45; ui="$ARCHPHENE_UI"; archphene_tap_ui_pattern "$ui" 'text="btop  [^"]+"' btop-result; archphene_wait_ui 'text="Add to apps"' repo-detail; ui="$ARCHPHENE_UI"; for expected in 'text="Repository"' 'text="Architecture"' 'text="Wrapper: built and signed on this device"'; do archphene_regex_contains "$ui" "$expected" || archphene_die "detail missing $expected"; done; archphene_tap_ui_pattern "$ui" 'text="Add to apps"' track; archphene_wait_ui 'text="Not installed"' repo-tracked; ui="$ARCHPHENE_UI"; [[ "$ui" == *'text="btop"'* ]] || archphene_die "tracked btop missing"; archphene_tap_ui_pattern "$ui" 'text="btop"' tracked; archphene_wait_ui 'text="Remove from apps"' repo-remove; archphene_tap_ui_pattern "$ARCHPHENE_UI" 'text="Remove from apps"' remove; archphene_note "Official Arch package search and tracked-package workflow passed."
